@implements IAsyncDisposable

<CascadingValue Value="currentSize" Name="ScreenSize">
    @ChildContent
</CascadingValue>

@code {
    [Parameter]
    public RenderFragment? ChildContent { get; set; }

    private ScreenSize currentSize = ScreenSize.Desktop;

    private IJSObjectReference? module;
    private DotNetObjectReference<ScreenSizeProvider>? dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/Components/ScreenSizeProvider.razor.js");
            await module.InvokeVoidAsync("initialize", dotNetRef);
        }
    }

    [JSInvokable]
    public void OnResize(int width)
    {
        var newSize = width switch
        {
            < 768 => ScreenSize.Mobile,
            < 1024 => ScreenSize.Tablet,
            _ => ScreenSize.Desktop
        };

        if (newSize != currentSize)
        {
            currentSize = newSize;
            StateHasChanged();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (module is not null)
        {
            await module.InvokeVoidAsync("dispose");
            await module.DisposeAsync();
        }

        dotNetRef?.Dispose();
    }
}

namespace sv_af4a4ac22f6a4a459779b6cc0e9cece2.Components;

public enum ScreenSize
{
    Mobile,
    Tablet,
    Desktop
}

let resizeHandler = null;

export function initialize(dotNetRef) {
    dotNetRef.invokeMethodAsync('OnResize', window.innerWidth);

    resizeHandler = () => {
        dotNetRef.invokeMethodAsync('OnResize', window.innerWidth);
    };

    window.addEventListener('resize', resizeHandler);
}

export function dispose() {
    if (resizeHandler) {
        window.removeEventListener('resize', resizeHandler);
        resizeHandler = null;
    }
}

